/**
 * Returns the [AppStrings] instance for the given BCP-47-style [langCode].
 *
 * Called from [MainActivity] on startup (reads the language persisted in SharedPreferences)
 * and from [OnboardingScreen] when the user selects a language from the picker.
 *
 * Falls back to [stringsEn] for any unrecognised or null language code, ensuring the app
 * always has a complete set of strings regardless of the device locale.
 *
 * @param langCode A two-letter language code such as "en", "it", "fr", "de", "es",
 *                 "zh", "ja", "ko", or "ru".
 * @return The matching [AppStrings] instance, or [stringsEn] if the code is not recognised.
 */
fun appStringsFor(langCode: String): AppStrings = when (langCode) {
    "it" -> stringsIt
    "fr" -> stringsFr
    "de" -> stringsDe
    "es" -> stringsEs
    "zh" -> stringsZh
    "ja" -> stringsJa
    "ko" -> stringsKo
    "ru" -> stringsRu
    else -> stringsEn
}
